// 1. Sadə interface extending
interface Person {
  name: string;
  age: number;
}
interface Employee extends Person {
  role: string;
}
const employee: Employee = {
  name: "Murad",
  age: 25,
  role: "Developer"
};
console.log(employee); // Çıxış: { name: "Murad", age: 25, role: "Developer" }

// 2. Çoxlu miras alma
interface Contact {
  email: string;
}
interface Manager extends Person, Contact {
  department: string;
}
const manager: Manager = {
  name: "Alice",
  age: 30,
  email: "alice@example.com",
  department: "IT"
};
console.log(manager); // Çıxış: { name: "Alice", age: 30, email: "alice@example.com", department: "IT" }

// 3. Optional və readonly xüsusiyyətlərlə
interface Vehicle {
  readonly brand: string;
  model?: string;
}
interface Car extends Vehicle {
  year: number;
}
const car: Car = {
  brand: "Toyota",
  year: 2020
};
console.log(car); // Çıxış: { brand: "Toyota", year: 2020 }
// car.brand = "Honda"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// 4. Siniflərdə interface extending
interface Animal {
  name: string;
  makeSound(): string;
}
interface Dog extends Animal {
  breed: string;
}
class Puppy implements Dog {
  name: string;
  breed: string;
  constructor(name: string, breed: string) {
    this.name = name;
    this.breed = breed;
  }
  makeSound(): string {
    return "Woof!";
  }
}
const puppy = new Puppy("Buddy", "Labrador");
console.log(puppy); // Çıxış: Puppy { name: "Buddy", breed: "Labrador" }
console.log(puppy.makeSound()); // Çıxış: Woof!

// 5. Union tipləri ilə interface extending
interface Book {
  type: "book";
  title: string;
  pages: number;
}
interface ExtendedBook extends Book {
  author: string;
}
interface Movie {
  type: "movie";
  title: string;
  duration: number;
}
type Media = ExtendedBook | Movie;
function describeMedia(media: Media): string {
  if (media.type === "book") {
    return `${media.title} by ${media.author}: ${media.pages} pages`;
  }
  return `${media.title}: ${media.duration} minutes`;
}
const book: ExtendedBook = { type: "book", title: "TypeScript Guide", pages: 200, author: "John" };
const movie: Movie = { type: "movie", title: "Inception", duration: 148 };
console.log(describeMedia(book)); // Çıxış: TypeScript Guide by John: 200 pages
console.log(describeMedia(movie)); // Çıxış: Inception: 148 minutes

// Sadə mağaza sistemi
interface Product {
  id: string;
  name: string;
  price: number;
}
interface StockProduct extends Product {
  stockCount: number;
  inStock?: boolean;
}

function displayProduct(product: StockProduct): string {
  return `${product.name} (ID: ${product.id}): $${product.price}, ${product.inStock ? "mövcuddur" : "mövcud deyil"}, ${product.stockCount} ədəd`;
}

const laptop: StockProduct = {
  id: "P001",
  name: "Laptop",
  price: 1200,
  inStock: true,
  stockCount: 10
};
console.log(displayProduct(laptop)); // Çıxış: Laptop (ID: P001): $1200, mövcuddur, 10 ədəd

// Çoxlu miras alma ilə
interface Discount {
  discount: number;
}
interface DiscountedStockProduct extends StockProduct, Discount {
  discountEndDate?: string;
}
const discountedLaptop: DiscountedStockProduct = {
  id: "P001",
  name: "Laptop",
  price: 1200,
  inStock: true,
  stockCount: 10,
  discount: 15,
  discountEndDate: "2025-12-31"
};
console.log(`${discountedLaptop.name}: ${discountedLaptop.discount}% endirim`); // Çıxış: Laptop: 15% endirim

