}

const laptop: StockProduct = {
  id: "P001",
  name: "Laptop",
  price: 1200,
  inStock: true,
  stockCount: 10
};
console.log(displayProduct(laptop)); // Output: Laptop (ID: P001): $1200, in stock, 10 units

