  id: "P001",
  name: "Laptop",
  price: 1200,
  inStock: true,
  stockCount: 10,
  discount: 15,
  discountEndDate: "2025-12-31"
};
console.log(`${discountedLaptop.name}: ${discountedLaptop.discount}% discount`); // Output: Laptop: 15% discount

